const row = Array.isArray($('Loop Over Items').item.json) ? ($('Loop Over Items').item.json[0] || {}) : $('Loop Over Items').item.json;

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function bool(value) {
  return Number(value || 0) === 1 || value === true;
}

const memoryCompact = {
  empresa: clean(row.company_name || row.lead_name),
  lead_name: clean(row.lead_name),
  lead_source_type: clean(row.lead_source_type),
  lead_status: clean(row.lead_status),
  fit_score: Number(row.fit_score || 0),

  responsavel_confirmado: bool(row.responsavel_confirmado),
  responsavel_terceiro: bool(row.responsavel_terceiro),
  origem_clientes_identificada: bool(row.origem_clientes_identificada),
  gargalo_identificado: bool(row.gargalo_identificado),
  pedido_preco: bool(row.pedido_preco),
  pedido_detalhes: bool(row.pedido_detalhes),
  handoff_realizado: bool(row.handoff_realizado),

  nome_responsavel: clean(row.nome_responsavel),
  origem_clientes: clean(row.origem_clientes),
  principal_gargalo: clean(row.principal_gargalo),
  interesse_em_crescer: clean(row.interesse_em_crescer),

  ultima_pergunta_feita: clean(row.ultima_pergunta_feita),
  ultima_mensagem_lead: clean(row.last_message),
  ultima_resposta_enviada: clean(row.last_response),

  resumo_conversa: clean(row.resumo_conversa),
  proximo_passo: clean(row.proximo_passo),
  observacoes: clean(row.observacoes),
};

return [
  {
    json: {
      memory_compact: memoryCompact
    }
  }
];

const NODE_VERSION = "v2_followup_normaliza_resposta_sem_vazio";

function readNode(name) {
  try {
    return $(name).item.json || {};
  } catch (error) {
    return {};
  }
}

function clean(value, preserveNewLines = false) {
  if (value === undefined || value === null) return "";

  let text = typeof value === "object"
    ? JSON.stringify(value)
    : String(value);

  text = text
    .replace(/\[object Object\]/gi, "")
    .replace(/[\u200B-\u200D\u2060\uFEFF]/g, " ")
    .replace(/\uFFFD/g, " ")
    .replace(/\r\n/g, "\n")
    .replace(/\r/g, "\n");

  if (preserveNewLines) {
    return text
      .split("\n")
      .map(line => line.replace(/[ \t]+/g, " ").trim())
      .filter(Boolean)
      .join("\n")
      .trim();
  }

  return text.replace(/\s+/g, " ").trim();
}

function parseJsonOutput(raw) {
  if (raw && typeof raw === "object" && !Array.isArray(raw)) {
    return {
      ok: true,
      data: raw,
      raw: JSON.stringify(raw),
      error: "",
    };
  }

  let text = clean(raw, true);

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  try {
    return {
      ok: true,
      data: JSON.parse(text),
      raw: text,
      error: "",
    };
  } catch (error) {
    const match = text.match(/\{[\s\S]*\}/);

    if (match) {
      try {
        return {
          ok: true,
          data: JSON.parse(match[0]),
          raw: text,
          error: "",
        };
      } catch (innerError) {
        return {
          ok: false,
          data: {},
          raw: text,
          error: innerError.message,
        };
      }
    }

    return {
      ok: false,
      data: {},
      raw: text,
      error: error.message,
    };
  }
}

function firstFilled(...values) {
  for (const value of values) {
    const text = clean(value, true);
    if (text) return text;
  }
  return "";
}

const current = $json || {};

const memoryNode = readNode("Prepara Memory Followup");
const memory = memoryNode.memory_compact || memoryNode || {};

const empresa = firstFilled(
  memory.empresa,
  memory.company_name,
  memory.lead_name,
  "a empresa"
);

const rawOutput =
  current.output ||
  current.text ||
  current.response ||
  current.result ||
  current.message ||
  current;

const parsed = parseJsonOutput(rawOutput);
const out = parsed.data || {};

let resposta = clean(out.resposta, true);

const fallbackResponse = `Bom dia! Passando só para retomar o ponto de ontem sobre a presença digital da ${empresa}. Deixo por aqui um resumo rápido para a pessoa responsável avaliar?`;

let usedFallback = false;

if (!resposta) {
  resposta = fallbackResponse;
  usedFallback = true;
}

return [
  {
    json: {
      should_send: true,
      should_reply: true,

      followup: {
        resposta,
        deve_enviar: true,
        motivo: clean(out.motivo) || (
          usedFallback
            ? "Fallback usado porque a resposta da Julia veio vazia ou inválida."
            : "Follow-up contextual gerado pela Julia."
        ),
        tipo_followup: clean(out.tipo_followup) || "reativacao_contextual",
        proximo_passo: clean(out.proximo_passo),
        used_fallback: usedFallback,
      },

      debug: {
        ...(current.debug || {}),

        normaliza_pos_julia_followup_version: NODE_VERSION,

        parse_ok: parsed.ok,
        parse_error: parsed.error,

        should_send: true,
        used_fallback: usedFallback,

        raw_output: parsed.raw,
      },
    },
  },
];

